import{_ as e,o as l,c as d,a2 as a}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"🤖 機器人相關台股個股清單","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/機器人研究/機器人研究_相關個股清單.md","filePath":"Deep32Q知識庫/產業洞察/機器人研究/機器人研究_相關個股清單.md"}'),n={name:"Deep32Q知識庫/產業洞察/機器人研究/機器人研究_相關個股清單.md"};function i(s,t,r,h,x,y){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="🤖-機器人相關台股個股清單" tabindex="-1">🤖 機器人相關台股個股清單 <a class="header-anchor" href="#🤖-機器人相關台股個股清單" aria-label="Permalink to &quot;🤖 機器人相關台股個股清單&quot;">​</a></h1><blockquote><p><strong>最後更新</strong>：2026-06-11 <strong>說明</strong>：收錄台股中與機器人產業相關的各環節個股，包含供應鏈定位、主要產品與風險提示</p></blockquote><hr><h2 id="一、上游-精密傳動元件" tabindex="-1">一、上游：精密傳動元件 <a class="header-anchor" href="#一、上游-精密傳動元件" aria-label="Permalink to &quot;一、上游：精密傳動元件&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司簡稱</th><th style="text-align:left;">供應鏈環節</th><th>主要產品/技術</th><th style="text-align:left;">競爭優勢</th><th style="text-align:left;">風險提示</th></tr></thead><tbody><tr><td style="text-align:center;">2049</td><td style="text-align:left;">上銀</td><td style="text-align:left;">減速機、線性滑軌、滾珠螺桿、關節模組</td><td>全球前三大線性傳動元件廠；開發諧波減速機+整合關節模組；2026 年物流機器人小量產</td><td style="text-align:left;">技術壁壘高、全球客戶網路完整、機器人營收 10%+ 目標</td><td style="text-align:left;">傳統自動化景氣循環影響本業；減速機量產時程不確定</td></tr><tr><td style="text-align:center;">1597</td><td style="text-align:left;">直得</td><td style="text-align:left;">微型線性滑軌、線性馬達、六軸手臂、關節模組</td><td>全球第三大微型線性滑軌廠；開發人形機器人關節模組</td><td style="text-align:left;">利基市場寡佔、漲價能力、半導體 CPO 設備需求加持</td><td style="text-align:left;">市值較小、產品線相對集中</td></tr><tr><td style="text-align:center;">4540</td><td style="text-align:left;">全球傳動</td><td style="text-align:left;">滾珠螺桿、線性滑軌、滾珠花鍵</td><td>自有品牌 TBI MOTION；中低階精密傳動</td><td style="text-align:left;">中國市場回溫、毛利率改善中</td><td style="text-align:left;">中國依賴度高（~40% 營收）、品牌溢價不及上銀</td></tr></tbody></table><hr><h2 id="二、上游-伺服馬達-電機" tabindex="-1">二、上游：伺服馬達 / 電機 <a class="header-anchor" href="#二、上游-伺服馬達-電機" aria-label="Permalink to &quot;二、上游：伺服馬達 / 電機&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司簡稱</th><th style="text-align:left;">供應鏈環節</th><th>主要產品/技術</th><th style="text-align:left;">競爭優勢</th><th style="text-align:left;">風險提示</th></tr></thead><tbody><tr><td style="text-align:center;">4576</td><td style="text-align:left;">大銀微系統</td><td style="text-align:left;">精密伺服馬達、力矩馬達、直驅系統、關節模組</td><td>上銀子公司；開發機器人整合型關節模組；晶圓機器人</td><td style="text-align:left;">與上銀形成垂直整合、半導體無塵室應用</td><td style="text-align:left;">獲利波動大、需跟上銀連動看待</td></tr><tr><td style="text-align:center;">2308</td><td style="text-align:left;">台達電</td><td style="text-align:left;">伺服系統、工業電源、散熱、工業自動化</td><td>台灣最大工業自動化廠商；開發協作型/人形專用馬達</td><td style="text-align:left;">產品線完整、品牌力強、AI 伺服器電源龍頭</td><td style="text-align:left;">機器人營收佔比仍低；高階伺服尚難敵日廠</td></tr></tbody></table><hr><h2 id="三、上游-控制器-ai-晶片-邊緣運算" tabindex="-1">三、上游：控制器 / AI 晶片 / 邊緣運算 <a class="header-anchor" href="#三、上游-控制器-ai-晶片-邊緣運算" aria-label="Permalink to &quot;三、上游：控制器 / AI 晶片 / 邊緣運算&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司簡稱</th><th style="text-align:left;">供應鏈環節</th><th>主要產品/技術</th><th style="text-align:left;">競爭優勢</th><th style="text-align:left;">風險提示</th></tr></thead><tbody><tr><td style="text-align:center;">7750</td><td style="text-align:left;">新代</td><td style="text-align:left;">PC-Based 控制器、AI 視覺整合、機器人控制器</td><td>台灣工具機控制器龍頭；蘇州二廠 Q3 啟用</td><td style="text-align:left;">高毛利率（~45%）、中國高階市佔擴大、法人預估 EPS 35.12 元</td><td style="text-align:left;">中國市場政策風險、工具機景氣循環</td></tr><tr><td style="text-align:center;">2395</td><td style="text-align:left;">研華</td><td style="text-align:left;">邊緣運算平台、工業物聯網、機器控制器</td><td>NVIDIA Isaac 平台合作夥伴；提供機器人邊緣運算硬體</td><td style="text-align:left;">全球工業電腦龍頭、客戶遍布全球</td><td style="text-align:left;">非純機器人概念、受益間接</td></tr><tr><td style="text-align:center;">5289</td><td style="text-align:left;">宜鼎</td><td style="text-align:left;">邊緣運算 AI 記憶體/儲存模組</td><td>針對 AI 應用的工業級記憶體、SSD</td><td style="text-align:left;">工業級質量認證、邊緣運算趨勢受惠</td><td style="text-align:left;">機器人佔比極低</td></tr><tr><td style="text-align:center;">2330</td><td style="text-align:left;">台積電</td><td style="text-align:left;">AI 晶圓代工（NVIDIA Jetson/Thor）</td><td>為 NVIDIA、Qualcomm、AMD 等機器人運算晶片代工</td><td style="text-align:left;">世界級製程領先、機器人用晶片量產後可觀</td><td style="text-align:left;">間接受益、非純機器人概念</td></tr></tbody></table><hr><h2 id="四、上游-ai-視覺-感測器" tabindex="-1">四、上游：AI 視覺 / 感測器 <a class="header-anchor" href="#四、上游-ai-視覺-感測器" aria-label="Permalink to &quot;四、上游：AI 視覺 / 感測器&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司簡稱</th><th style="text-align:left;">供應鏈環節</th><th>主要產品/技術</th><th style="text-align:left;">競爭優勢</th><th style="text-align:left;">風險提示</th></tr></thead><tbody><tr><td style="text-align:center;">2359</td><td style="text-align:left;">所羅門</td><td style="text-align:left;">AI 視覺辨識、3D 感測、機器人視覺引導</td><td>台灣 AI 視覺標竿；與 NVIDIA Isaac 平台整合</td><td style="text-align:left;">軟體授權高毛利、跨品牌整合能力</td><td style="text-align:left;">半導體以外的應用場景仍需驗證、競爭對手(Keyence/Cognex)強大</td></tr><tr><td style="text-align:center;">2382</td><td style="text-align:left;">廣達</td><td style="text-align:left;">AI 視覺、機器人製造</td><td>子公司廣明光電 - 達明機器人</td><td style="text-align:left;">AI 伺服器大廠，具備 AI 軟硬體整合實力</td><td style="text-align:left;">機器人非主營業務</td></tr></tbody></table><hr><h2 id="五、中游-機器人本體製造" tabindex="-1">五、中游：機器人本體製造 <a class="header-anchor" href="#五、中游-機器人本體製造" aria-label="Permalink to &quot;五、中游：機器人本體製造&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司簡稱</th><th style="text-align:left;">供應鏈環節</th><th>主要產品/技術</th><th style="text-align:left;">競爭優勢</th><th style="text-align:left;">風險提示</th></tr></thead><tbody><tr><td style="text-align:center;">6188</td><td style="text-align:left;">廣明光電</td><td style="text-align:left;">協作型機器人品牌</td><td>子公司達明機器人(TM Robot)，全球協作機器人 Top 5</td><td style="text-align:left;">少數 AI 視覺內建機器人品牌、亞洲市場知名度</td><td style="text-align:left;">協作型市場競爭加劇(UR、Fanuc、ABB 等)</td></tr><tr><td style="text-align:center;">2317</td><td style="text-align:left;">鴻海</td><td style="text-align:left;">機器人 OEM 代工、自有品牌 FoxBot</td><td>大規模精密製造，為 Tesla/Optimus、Figure AI 潛在代工夥伴</td><td style="text-align:left;">世界級製造規模、供應鏈管理能力</td><td style="text-align:left;">代工合約尚未確認、機器人非主業</td></tr><tr><td style="text-align:center;">2464</td><td style="text-align:left;">盟立</td><td style="text-align:left;">自動化設備、人形機器人零件/組裝</td><td>AGV/AMR、天車(OHT)；轉投資盟英科技(人形機器人核心零件)</td><td style="text-align:left;">半導體 AMR 實績、產官學合作網絡</td><td style="text-align:left;">人形機器人投資尚在早期、營收貢獻低</td></tr></tbody></table><hr><h2 id="六、中游-線束-連接器" tabindex="-1">六、中游：線束 / 連接器 <a class="header-anchor" href="#六、中游-線束-連接器" aria-label="Permalink to &quot;六、中游：線束 / 連接器&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司簡稱</th><th style="text-align:left;">供應鏈環節</th><th>主要產品/技術</th><th style="text-align:left;">競爭優勢</th><th style="text-align:left;">風險提示</th></tr></thead><tbody><tr><td style="text-align:center;">3023</td><td style="text-align:left;">信邦</td><td style="text-align:left;">機內線束、連接器、電源訊號傳輸方案</td><td>美國三大機器人品牌<strong>單一供應商</strong>；助攻全套機內解決方案</td><td style="text-align:left;">客製化設計+高黏著度、單一供應商地位</td><td style="text-align:left;">機器人營收 2027 年才顯著放量</td></tr><tr><td style="text-align:center;">6205</td><td style="text-align:left;">詮欣</td><td style="text-align:left;">連接器</td><td>次要供應商</td><td style="text-align:left;">—</td><td style="text-align:left;">角色邊緣</td></tr><tr><td style="text-align:center;">2392</td><td style="text-align:left;">正崴</td><td style="text-align:left;">連接器、電池模組</td><td>間接供應連接器</td><td style="text-align:left;">—</td><td style="text-align:left;">曝險極低</td></tr></tbody></table><hr><h2 id="七、中下游-系統整合-amr" tabindex="-1">七、中下游：系統整合 / AMR <a class="header-anchor" href="#七、中下游-系統整合-amr" aria-label="Permalink to &quot;七、中下游：系統整合 / AMR&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司簡稱</th><th style="text-align:left;">供應鏈環節</th><th>主要產品/技術</th><th style="text-align:left;">競爭優勢</th><th style="text-align:left;">風險提示</th></tr></thead><tbody><tr><td style="text-align:center;">6438</td><td style="text-align:left;">迅得</td><td style="text-align:left;">半導體 AMR、自動化 OHT</td><td>半導體產業自動化搬運系統</td><td style="text-align:left;">半導體擴廠剛需</td><td style="text-align:left;">客戶集中度高</td></tr><tr><td style="text-align:center;">6125</td><td style="text-align:left;">廣運</td><td style="text-align:left;">自動化物流系統、AGV</td><td>自動化倉儲、物流設備整合</td><td style="text-align:left;">台灣物流自動化先驅</td><td style="text-align:left;">市場區域局限</td></tr><tr><td style="text-align:center;">8374</td><td style="text-align:left;">羅昇</td><td style="text-align:left;">設備代工（亞馬遜搬運機器人）</td><td>代工製造搬運機器人</td><td style="text-align:left;">穩定代工收入</td><td style="text-align:left;">代工利潤薄、訂單波動</td></tr></tbody></table><hr><h2 id="八、投資方向摘要" tabindex="-1">八、投資方向摘要 <a class="header-anchor" href="#八、投資方向摘要" aria-label="Permalink to &quot;八、投資方向摘要&quot;">​</a></h2><h3 id="🟢-核心曝險-機器人佔比高、營收可量化" tabindex="-1">🟢 核心曝險（機器人佔比高、營收可量化） <a class="header-anchor" href="#🟢-核心曝險-機器人佔比高、營收可量化" aria-label="Permalink to &quot;🟢 核心曝險（機器人佔比高、營收可量化）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">優先級</th><th style="text-align:center;">股號</th><th style="text-align:left;">公司</th><th>核心理由</th></tr></thead><tbody><tr><td style="text-align:center;">⭐⭐⭐</td><td style="text-align:center;">2049</td><td style="text-align:left;">上銀</td><td>最純機器人概念台股，從傳動元件到關節模組到物流機器人全面布局</td></tr><tr><td style="text-align:center;">⭐⭐⭐</td><td style="text-align:center;">3023</td><td style="text-align:left;">信邦</td><td>單一供應商地位，2026-27 美系客戶量產爆發</td></tr><tr><td style="text-align:center;">⭐⭐⭐</td><td style="text-align:center;">1597</td><td style="text-align:left;">直得</td><td>微型滑軌寡佔，漲價+接單能見度延長，營收 YoY 強勁</td></tr></tbody></table><h3 id="🟡-策略性曝險-ai-控制器-視覺軟體" tabindex="-1">🟡 策略性曝險（AI/控制器/視覺軟體） <a class="header-anchor" href="#🟡-策略性曝險-ai-控制器-視覺軟體" aria-label="Permalink to &quot;🟡 策略性曝險（AI/控制器/視覺軟體）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">優先級</th><th style="text-align:center;">股號</th><th style="text-align:left;">公司</th><th>核心理由</th></tr></thead><tbody><tr><td style="text-align:center;">⭐⭐</td><td style="text-align:center;">2359</td><td style="text-align:left;">所羅門</td><td>AI 視覺軟體授權毛利高、跨品牌應用</td></tr><tr><td style="text-align:center;">⭐⭐</td><td style="text-align:center;">7750</td><td style="text-align:left;">新代</td><td>控制器轉型機器人、高毛利率、中國成長</td></tr><tr><td style="text-align:center;">⭐⭐</td><td style="text-align:center;">2308</td><td style="text-align:left;">台達電</td><td>工業自動化龍頭，機器人為長期成長引擎</td></tr></tbody></table><h3 id="🟠-觀察清單-尚未確認或間接" tabindex="-1">🟠 觀察清單（尚未確認或間接） <a class="header-anchor" href="#🟠-觀察清單-尚未確認或間接" aria-label="Permalink to &quot;🟠 觀察清單（尚未確認或間接）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">優先級</th><th style="text-align:center;">股號</th><th style="text-align:left;">公司</th><th>觀察重點</th></tr></thead><tbody><tr><td style="text-align:center;">⭐</td><td style="text-align:center;">2317</td><td style="text-align:left;">鴻海</td><td>Tesla Optimus 代工訂單確認</td></tr><tr><td style="text-align:center;">⭐</td><td style="text-align:center;">2464</td><td style="text-align:left;">盟立</td><td>盟英科技人形機器人零組件量產</td></tr><tr><td style="text-align:center;">⭐</td><td style="text-align:center;">6188</td><td style="text-align:left;">廣明/達明</td><td>協作機器人全球市佔成長率</td></tr></tbody></table><hr><h2 id="九、資料來源" tabindex="-1">九、資料來源 <a class="header-anchor" href="#九、資料來源" aria-label="Permalink to &quot;九、資料來源&quot;">​</a></h2><ul><li>Yahoo 股市，機器人/智慧機械概念股行情</li><li>CMoney，《2026機器人概念股》</li><li>Stockfeel，《機器人概念股正火燙：人形機器人是什麼？》</li><li>TEJ，《認識機器人產業》</li><li>Digitimes, Taiwan robotics supply chain posts strong 1Q26 gains</li><li>永豐金證券，Computex 2026 參觀攻略</li><li>Instagram/Taiwan News, Hiwin logistics robots</li></ul>',34)])])}const o=e(n,[["render",i]]);export{f as __pageData,o as default};
